#include<bits/stdc++.h>
using namespace std;
struct edge
{
    int u,v,w;
    bool operator<(const edge&b)const
    {
        return w>b.w;
    }
}a[1000010],b[1000010];
int n,m,q,tot,lst,lson[1000010],rson[1000010],siz[1000010],d[1000010],fa[1000010],f[1000010][21],w[1000010];
vector<pair<int,int>> v;
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void kruskal()
{
    sort(a+1,a+1+m);
    for(int i=1;i<=m;i++)
    {
        int u=find(a[i].u),v=find(a[i].v);
        if(u!=v)
        {
            w[++tot]=a[i].w;
            fa[u]=fa[v]=tot;
            lson[tot]=u;
            rson[tot]=v;
        }
    }
}
void dfs(int x,int fa=0)
{
    f[x][0]=fa;
    d[x]=d[fa]+1;
    for(int i=1;i<=20;i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    if(x<=n)
    {
        siz[x]=1;
    }
    else
    {
        dfs(lson[x],x);
        dfs(rson[x],x);
        siz[x]=siz[lson[x]]+siz[rson[x]];
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    for(int i=20;i>=0;i--)
    {
        if(d[f[x][i]]>=d[y])
        {
            x=f[x][i];
        }
    }
    if(x==y)
    {
        return x;
    }
    for(int i=20;i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
int query(int x)
{
    for(int i=20;i>=0;i--)
    {
        if(f[x][i]&&w[f[x][i]]>=lst)
        {
            x=f[x][i];
        }
    }
    return siz[x];
}
int main()
{
    scanf("%d%d%d",&n,&m,&q);
    tot=n;
    for(int i=1;i<=n*2;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&a[i].u,&a[i].v,&a[i].w);
        b[i]=a[i];
    }
    kruskal();
    for(int i=tot;i>=1;i--)
    {
        if(siz[i]==0)
        {
            dfs(i);
        }
    }
    while(q--)
    {
        int op,x,y;
        scanf("%d%d",&op,&x);
        if(op==1)
        {
            for(auto i:v)
            {
                w[i.first]=i.second;
            }
            v.clear();
            lst=x;
        }
        else if(op==2)
        {
            printf("%d\n",query(x));
        }
        else
        {
            scanf("%d",&y);
            int l=lca(b[x].u,b[x].v);
            if(w[l]!=b[x].w)
            {
                continue;
            }
            v.push_back({l,b[x].w=y});
        }
    }
    return 0;
}
